package be.schaubroeck.lpb.rkm.rekenmotor;

import be.schaubroeck.lpb.rkm.rekenmotor.util.LoonElementManager;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Persoon;

import java.util.Collection;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenBasisRszKey.BASIS_BIJZONDERE_BIJDRAGE_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.LOONELEMENT_MANAGER_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenRszKey.BIJZONDERE_BIJDRAGE_KEY;

public class OvernemenBijzondereBijdrage extends AbstractRekenCommand {

    @Override
    protected boolean execute(RekenContext context) {
        RekenContext preBerekeningContext = context.getUnchecked(RekenTools.bepaalVorigeBerekeningType(context));
        if (!preBerekeningContext.isEmpty()) {
            overnemenBijzonderBijdrage(context, preBerekeningContext);
        }

        return CONTINUE_PROCESSING;
    }

    private void overnemenBijzonderBijdrage(RekenContext mainContext, RekenContext preBerekeningContext) {
        LoonElementManager loonElementManager = mainContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        LoonElementManager prevLoonElementManager = preBerekeningContext.getUnchecked(LOONELEMENT_MANAGER_KEY);

        Money bijzondereBijdrage = preBerekeningContext.getMoney(BIJZONDERE_BIJDRAGE_KEY);
        mainContext.put(BIJZONDERE_BIJDRAGE_KEY, bijzondereBijdrage);

        Persoon persoon = mainContext.getUnchecked(PERSOON_KEY);

        for (Opdracht opdracht : persoon.getOpdrachten()) {
            Collection<LoonElement> prevLoonElementen = prevLoonElementManager.getOpdrachtsElementen(opdracht);
            RekenTools.overnemenVanVorigeBerekening(BASIS_BIJZONDERE_BIJDRAGE_KEY, loonElementManager, prevLoonElementen);
            RekenTools.overnemenVanVorigeBerekening(BIJZONDERE_BIJDRAGE_KEY, loonElementManager, prevLoonElementen);
        }
    }


}
